Here's the refactored code with the context and helper function combined into a custom hook:

**Custom Hook: useNotification**

```typescript
// @/src/hooks/useNotification.ts
import { createContext, useContext, useState, useEffect } from 'react';

interface NotificationProps {
  heading: string;
  subheading: string;
  type: string;
}

interface useNotificationReturn {
  notify: (props: NotificationProps) => void;
  notificationElem: HTMLHuelNotificationElement | | null;
}

const NotificationContext = createContext<useNotificationReturn | null>(null);

const useNotification = (): useNotificationReturn => {
  const [notificationElem, setNotificationElem] = useState<HTMLHuelNotificationElement | null>(null);

  useEffect(() => {
    const element = document.querySelector('huel-notification');
    if (element) {
      setNotificationElem(element);
    }
  }, []);

  const notify = async (props: NotificationProps) => {
    if (!notificationElem) return;

    const { heading, subheading, type } = props;
    await notificationElem.open({
      heading,
      subheading,
      type,
    });
  };

  return { notify, notificationElem };
};

export default useNotification;
```

